const express = require('express');
const twilio = require('twilio');
const redis = require('redis');
const bodyParser = require('body-parser');
const crypto = require('crypto');

const app = express();
const client = redis.createClient();
const twilioClient = twilio('TWILIO_ACCOUNT_SID', 'TWILIO_AUTH_TOKEN');

app.use(bodyParser.json());

const generateCode = () => Math.floor(100000 + Math.random() * 900000).toString();

const sendSMS = (to, code) => {
    return twilioClient.messages.create({
        body: `Your verification code is: ${code}`,
        from: 'YOUR_TWILIO_PHONE_NUMBER',
        to: to
    });
};

app.post('/request-code', async (req, res) => {
    const { phoneNumber } = req.body;

    if (!/^\+\d{1,15}$/.test(phoneNumber)) {
        return res.status(400).send('Invalid phone number format.');
    }

    const code = generateCode();
    await sendSMS(phoneNumber, code);
    await client.setex(phoneNumber, 600, code);
    await client.setex(`${phoneNumber}:attempts`, 600, 0);

    res.status(200).send('Verification code sent.');
});

app.post('/verify-code', async (req, res) => {
    const { phoneNumber, code } = req.body;

    if (!/^\+\d{1,15}$/.test(phoneNumber) || !/^\d{6}$/.test(code)) {
        return res.status(400).send('Invalid input.');
    }

    const storedCode = await client.get(phoneNumber);
    const attempts = await client.get(`${phoneNumber}:attempts`);

    if (attempts >= 10) {
        return res.status(403).send('Too many attempts. Please try again later.');
    }

    if (storedCode === code) {
        await client.del(phoneNumber);
        await client.del(`${phoneNumber}:attempts`);
        res.status(200).send('Access granted.');
    } else {
        await client.incr(`${phoneNumber}:attempts`);
        res.status(401).send('Invalid code. Attempts: ' + (parseInt(attempts) + 1));
    }
});

